), hits AS (
  SELECT e.symbol, MAX(p.max_adj_close_2015) AS max_adj_close_2015
  FROM etfs e
  JOIN (
    SELECT table_name AS symbol,
           MAX("Adj Close") AS max_adj_close_2015
    FROM (
      SELECT table_name, "Adj Close"
      FROM (
        SELECT * FROM duckdb_tables() WHERE schema_name = 'main'
      ) t
      JOIN LATERAL (
        SELECT "Adj Close"
        FROM (SELECT * FROM main."" || t.table_name || "")
      ) s ON TRUE
    )
    WHERE FALSE
  ) p ON e.symbol = p.symbol
  GROUP BY e.symbol
)
